section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/market-analysis.json",
  "title": "Market Analysis",
  "type": "object",
  "required": [
    "artefact_id",
    "market_definition",
    "segments",
    "growth_drivers",
    "forces",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "market_definition": {
      "type": "string",
      "description": "explicit scope statement",
      "minLength": 1
    },
    "segments": {
      "type": "array",
      "description": "named segments + size estimates",
      "minItems": 1
    },
    "growth_drivers": {
      "type": "array",
      "description": "\u22653 cited drivers",
      "minItems": 1
    },
    "forces": {
      "type": "object",
      "description": "PEST/STEEP table with citations"
    },
    "regulation_notes": {
      "type": "array",
      "description": "applicable regulatory shifts",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "market-analysis-2026-05-23",
  "market_definition": "draft",
  "segments": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "growth_drivers": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "forces": {
    "key": "value"
  },
  "regulation_notes": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
